/**
 * User List Page
 *
 * Admin page for viewing and managing all users.
 * Features:
 * - Paginated user list
 * - Search by email
 * - User actions (view, enable/disable, delete, reset password)
 */

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAdmin } from '../../hooks/useAdmin';
import type { AdminUserDto } from 'shared';
import LoadingSpinner from '../../components/LoadingSpinner';
import ErrorMessage from '../../components/ErrorMessage';
import AdminPageHeader from '../../components/AdminPageHeader';

interface ResetPasswordResult {
  email: string;
  message: string;
  passwordViewLink?: string;
}

const UserListPage: React.FC = () => {
  const navigate = useNavigate();
  const admin = useAdmin();
  const [users, setUsers] = useState<AdminUserDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [paginationToken, setPaginationToken] = useState<string | null>(null);
  const [search, setSearch] = useState('');
  const [resetResult, setResetResult] = useState<ResetPasswordResult | null>(null);

  const fetchUsers = async (token?: string) => {
    setLoading(true);
    setError(null);
    try {
      const response = await admin.listUsers({
        paginationToken: token,
        search: search || undefined,
        limit: 20,
      });
      setUsers(response.users);
      setPaginationToken(response.paginationToken || null);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to fetch users');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchUsers();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    fetchUsers();
  };

  const handleEnableUser = async (userId: string) => {
    if (!confirm('Enable this user?')) return;
    try {
      await admin.enableUser(userId);
      fetchUsers(); // Refresh list
    } catch (err) {
      alert(err instanceof Error ? err.message : 'Failed to enable user');
    }
  };

  const handleDisableUser = async (userId: string) => {
    if (!confirm('Disable this user?')) return;
    try {
      await admin.disableUser(userId);
      fetchUsers(); // Refresh list
    } catch (err) {
      alert(err instanceof Error ? err.message : 'Failed to disable user');
    }
  };

  const handleDeleteUser = async (userId: string, email: string) => {
    if (!confirm(`Delete user ${email}? This action cannot be undone.`)) return;
    try {
      await admin.deleteUser(userId);
      fetchUsers(); // Refresh list
    } catch (err) {
      alert(err instanceof Error ? err.message : 'Failed to delete user');
    }
  };

  const handleResetPassword = async (userId: string, email: string) => {
    if (
      !confirm(
        `Reset password for ${email}?\n\nA one-time password link will be sent to the user's email.`
      )
    )
      return;
    setResetResult(null);
    try {
      const result = await admin.resetPassword(userId);
      setResetResult({ email, message: result.message, passwordViewLink: result.passwordViewLink });
    } catch (err) {
      alert(err instanceof Error ? err.message : 'Failed to reset password');
    }
  };

  return (
    <div className="container mx-auto px-4 py-8">
      <AdminPageHeader
        title="User Management"
        action={{ label: 'Create User', onClick: () => navigate('/admin/users/create') }}
      />

      {/* Search Form */}
      <form onSubmit={handleSearch} className="mb-6">
        <div className="flex gap-2">
          <input
            type="text"
            placeholder="Search by email..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="flex-1 px-4 py-2 border border-gray-300 rounded focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
          <button
            type="submit"
            className="bg-gray-600 text-white px-6 py-2 rounded hover:bg-gray-700"
          >
            Search
          </button>
          {search && (
            <button
              type="button"
              onClick={() => {
                setSearch('');
                fetchUsers();
              }}
              className="bg-gray-400 text-white px-4 py-2 rounded hover:bg-gray-500"
            >
              Clear
            </button>
          )}
        </div>
      </form>

      {/* Reset Password Result */}
      {resetResult && (
        <div className="mb-6 bg-green-50 border-l-4 border-green-400 p-4 rounded">
          <div className="flex justify-between items-start">
            <div className="flex-1">
              <p className="text-sm font-medium text-green-800">{resetResult.message}</p>
              <p className="text-xs text-green-700 mt-1">Target user: {resetResult.email}</p>
              {resetResult.passwordViewLink ? (
                <div className="mt-3">
                  <p className="text-xs text-green-700 mb-1">
                    Email sending failed. Please share this one-time password link with the user
                    manually:
                  </p>
                  <div className="bg-white rounded p-2 border border-green-200">
                    <code className="text-xs text-gray-700 break-all">
                      {resetResult.passwordViewLink}
                    </code>
                  </div>
                  <button
                    onClick={() => navigator.clipboard.writeText(resetResult.passwordViewLink!)}
                    className="mt-2 text-xs bg-green-600 text-white px-3 py-1 rounded hover:bg-green-700"
                  >
                    Copy link
                  </button>
                </div>
              ) : (
                <p className="text-xs text-green-600 mt-1">
                  A one-time password link has been sent to the user&apos;s email. The link is valid
                  for 24 hours.
                </p>
              )}
            </div>
            <button
              onClick={() => setResetResult(null)}
              className="ml-4 text-green-600 hover:text-green-800 text-lg font-bold"
            >
              ×
            </button>
          </div>
        </div>
      )}

      {/* Error Message */}
      {error && <ErrorMessage message={error} />}

      {/* Loading Spinner */}
      {loading && (
        <div className="flex justify-center py-8">
          <LoadingSpinner size="large" text="Loading users..." />
        </div>
      )}

      {/* User Table */}
      {!loading && !error && (
        <>
          <div className="bg-white shadow-md rounded overflow-x-auto">
            <table className="min-w-full">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Email
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Name
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Status
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Groups
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Created
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {users.length === 0 ? (
                  <tr>
                    <td colSpan={6} className="px-6 py-4 text-center text-gray-500">
                      No users found
                    </td>
                  </tr>
                ) : (
                  users.map((user) => (
                    <tr key={user.userId} className="hover:bg-gray-50">
                      <td className="px-6 py-4 whitespace-nowrap">
                        <div className="text-sm font-medium text-gray-900">{user.email}</div>
                        {!user.emailVerified && (
                          <div className="text-xs text-red-500">Not verified</div>
                        )}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                        {user.name || '-'}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <span
                          className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${
                            user.enabled ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'
                          }`}
                        >
                          {user.enabled ? 'Active' : 'Disabled'}
                        </span>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                        {user.groups?.join(', ') || '-'}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                        {new Date(user.createdAt).toLocaleDateString()}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm font-medium space-x-2">
                        {user.enabled ? (
                          <button
                            onClick={() => handleDisableUser(user.userId)}
                            className="text-yellow-600 hover:text-yellow-900"
                          >
                            Disable
                          </button>
                        ) : (
                          <button
                            onClick={() => handleEnableUser(user.userId)}
                            className="text-green-600 hover:text-green-900"
                          >
                            Enable
                          </button>
                        )}
                        <button
                          onClick={() => handleResetPassword(user.userId, user.email)}
                          className="text-blue-600 hover:text-blue-900"
                        >
                          Reset Password
                        </button>
                        <button
                          onClick={() => handleDeleteUser(user.userId, user.email)}
                          className="text-red-600 hover:text-red-900"
                        >
                          Delete
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>

          {/* Pagination */}
          {paginationToken && (
            <div className="mt-4 flex justify-center">
              <button
                onClick={() => fetchUsers(paginationToken)}
                className="bg-gray-600 text-white px-6 py-2 rounded hover:bg-gray-700"
              >
                Load More
              </button>
            </div>
          )}
        </>
      )}
    </div>
  );
};

export default UserListPage;
